-- =============================================================================
-- SMART QUIZ SYSTEM - ClickHouse SEED DATA
-- =============================================================================
-- Dữ liệu mẫu 30 ngày để demo dashboard / materialized view.
-- Chạy sau schema.sql:
--   clickhouse-client --multiquery < seed.sql
--
-- LƯU Ý: ClickHouse Values parser khi đi qua `--multiquery` cắt statement
